// Keys map to the logo paths used in ENTITY_DEFINITIONS and branding.

/** Pre-baked logo data URIs keyed by logo filename stem. Null when file was missing at build time. */
export const BAKED_LOGOS: Record<string, string | null> = {
  "cardealer_ai": "data:image/png;base64,",
  "t3_marketing": "data:image/png;base64,",
  "topmrktr": "data:image/png;base64,",
  "smile_more": "data:image/png;base64,",
  "portfolio": "data:image/png;base64,",
  "financeos_lockup_light": "data:image/png;base64,",
};

/**
 * Maps the logo paths from ENTITY_DEFINITIONS (e.g. '/logos/cardealer-ai.png')
 * to their pre-baked data URI. Returns null if the logo was not found at build time.
 */
export function getBakedLogo(logoPath: string | null): string | null {
  if (!logoPath) return null;
  // Normalise: strip leading slash, strip path prefix, strip extension
  const file = logoPath.replace(/^\/+/, '').split('/').pop() ?? '';
  const key = file.replace(/\.[^.]+$/, '').replace(/-/g, '_');
  return BAKED_LOGOS[key] ?? null;
}
